import { useState, useEffect, useRef } from "react";

const C = {
  bg: "#FFF5F8", primary: "#7D1B2B", secondary: "#C8294A",
  light: "#F5A7C0", veryLight: "#FDEEF4", text: "#1A0810",
  muted: "#6B3A48", green: "#2A6B45", gold: "#B8860B",
  purple: "#5E2CA5", rose: "#E8527A", white: "#FFFFFF",
};

// ─── HOOKS ─────────────────────────────────────────────────────────────────
function useInView(thresh = 0.12) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVisible(true); obs.disconnect(); }
    }, { threshold: thresh });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [thresh]);
  return [ref, visible];
}

function useCount(target, active) {
  const [n, setN] = useState(0);
  useEffect(() => {
    if (!active || !target) return;
    let cur = 0;
    const step = Math.max(1, Math.ceil(target / 60));
    const t = setInterval(() => {
      cur = Math.min(cur + step, target);
      setN(cur);
      if (cur >= target) clearInterval(t);
    }, 16);
    return () => clearInterval(t);
  }, [target, active]);
  return n;
}

// ─── ANIMATED WRAPPER ──────────────────────────────────────────────────────
function FadeIn({ children, delay = 0, dir = "up" }) {
  const [ref, vis] = useInView();
  const tx = dir === "left" ? "-40px,0" : dir === "right" ? "40px,0" : "0,40px";
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? "translate(0,0)" : `translate(${tx})`,
      transition: `opacity 0.75s ease ${delay}ms, transform 0.75s ease ${delay}ms`,
    }}>{children}</div>
  );
}

// ─── COUNTER ───────────────────────────────────────────────────────────────
function Counter({ target, suffix = "" }) {
  const [ref, vis] = useInView();
  const n = useCount(target, vis);
  return <span ref={ref}>{n}{suffix}</span>;
}

// ─── BUBBLE ────────────────────────────────────────────────────────────────
function Bubble({ text, isMe, tag }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems: isMe?"flex-end":"flex-start", marginBottom:10 }}>
      {tag && <span style={{ fontSize:10, color:C.muted, fontWeight:700, marginBottom:3, [isMe?"marginRight":"marginLeft"]:8 }}>{tag}</span>}
      <div style={{
        maxWidth:"80%", padding:"11px 16px",
        borderRadius: isMe ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
        background: isMe ? C.primary : C.white,
        color: isMe ? "#fff" : C.text,
        fontSize:14, lineHeight:1.55,
        boxShadow:"0 2px 10px rgba(0,0,0,.09)",
      }}>{text}</div>
    </div>
  );
}

// ─── STAT CARD ─────────────────────────────────────────────────────────────
function Stat({ icon, label, value, suffix="", special, accent, dark }) {
  const [ref, vis] = useInView();
  const n = useCount(typeof value === "number" ? value : 0, vis);
  return (
    <div ref={ref} style={{
      background: dark ? accent : C.white,
      borderRadius:20, padding:"24px 14px", textAlign:"center",
      boxShadow: dark ? `0 6px 28px ${accent}55` : "0 4px 18px rgba(125,27,43,.09)",
      border: dark ? "none" : `2px solid ${C.veryLight}`,
      color: dark ? "#fff" : C.text,
      transform: vis ? "scale(1)" : "scale(.8)",
      opacity: vis ? 1 : 0,
      transition: "transform .55s ease, opacity .55s ease",
    }}>
      <div style={{ fontSize:32, marginBottom:6 }}>{icon}</div>
      <div style={{ fontSize:30, fontWeight:900, color: dark?"#fff":accent, letterSpacing:"-1px", lineHeight:1 }}>
        {special || (typeof value === "number" ? <>{n}{suffix}</> : value)}
      </div>
      <div style={{ fontSize:11, marginTop:6, fontWeight:600, color: dark?"rgba(255,255,255,.8)":C.muted, lineHeight:1.4 }}>{label}</div>
    </div>
  );
}

// ─── METER ─────────────────────────────────────────────────────────────────
function Meter({ label, pct, color }) {
  const [ref, vis] = useInView();
  return (
    <div ref={ref} style={{ marginBottom:16 }}>
      <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
        <span style={{ fontSize:13, fontWeight:600, color:C.text }}>{label}</span>
        <span style={{ fontSize:13, fontWeight:800, color }}>{pct}%</span>
      </div>
      <div style={{ background:C.veryLight, borderRadius:50, height:10, overflow:"hidden" }}>
        <div style={{ width: vis?`${pct}%`:"0%", height:"100%", background:`linear-gradient(90deg,${color}88,${color})`, borderRadius:50, transition:"width 1.6s ease .3s" }} />
      </div>
    </div>
  );
}

// ─── TIMELINE ITEM ─────────────────────────────────────────────────────────
function TItem({ date, icon, title, desc, flip, accent }) {
  const [ref, vis] = useInView();
  const ac = accent || C.primary;
  return (
    <div ref={ref} style={{
      display:"flex", flexDirection: flip?"row-reverse":"row", gap:14, marginBottom:28, alignItems:"flex-start",
      opacity: vis?1:0,
      transform: vis?"translate(0,0)":`translate(${flip?"30px":"−30px"},0)`,
      transition:"opacity .65s ease, transform .65s ease",
    }}>
      <div style={{ width:52, height:52, borderRadius:"50%", background:ac, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, boxShadow:`0 4px 14px ${ac}55` }}>{icon}</div>
      <div style={{ flex:1, background:C.white, borderRadius:16, padding:"16px 20px", boxShadow:"0 2px 12px rgba(0,0,0,.07)", borderLeft: flip?"none":`4px solid ${ac}`, borderRight: flip?`4px solid ${ac}`:"none" }}>
        <div style={{ fontSize:10, color:ac, fontWeight:700, textTransform:"uppercase", letterSpacing:"1.5px", marginBottom:4 }}>{date}</div>
        <div style={{ fontSize:15, fontWeight:800, color:C.primary, marginBottom:5 }}>{title}</div>
        <div style={{ fontSize:13, color:C.muted, lineHeight:1.65 }}>{desc}</div>
      </div>
    </div>
  );
}

// ─── FACT CARD ─────────────────────────────────────────────────────────────
function Fact({ emoji, title, desc, color }) {
  const [ref, vis] = useInView();
  return (
    <div ref={ref} style={{
      background:C.white, borderRadius:18, padding:22,
      boxShadow:"0 4px 18px rgba(0,0,0,.08)", borderTop:`4px solid ${color}`,
      opacity: vis?1:0, transform: vis?"translateY(0)":"translateY(24px)",
      transition:"opacity .55s ease, transform .55s ease",
    }}>
      <div style={{ fontSize:30, marginBottom:10 }}>{emoji}</div>
      <div style={{ fontSize:15, fontWeight:800, color:C.text, marginBottom:7 }}>{title}</div>
      <div style={{ fontSize:13, color:C.muted, lineHeight:1.65 }}>{desc}</div>
    </div>
  );
}

// ─── SECTION HEADER ────────────────────────────────────────────────────────
function SHead({ cap, title, sub }) {
  return (
    <div style={{ textAlign:"center", marginBottom:40 }}>
      <div style={{ fontSize:11, color:C.secondary, fontWeight:700, letterSpacing:"3px", textTransform:"uppercase", marginBottom:10 }}>{cap}</div>
      <h2 style={{ fontSize:"clamp(22px,5vw,34px)", fontWeight:900, color:C.text, margin:0, lineHeight:1.2 }}>{title}</h2>
      {sub && <p style={{ color:C.muted, marginTop:10, fontSize:14, lineHeight:1.6 }}>{sub}</p>}
    </div>
  );
}

