// ─── PHOTO CARD — imagen completa, sin recorte, fondo blur ─────────────────
function PhotoCard({ label, desc, src }) {
  const [h, setH] = useState(false);
  const [err, setErr] = useState(false);

  if (src && !err) {
    return (
      <div
        onMouseEnter={() => setH(true)}
        onMouseLeave={() => setH(false)}
        style={{
          borderRadius: 20,
          overflow: "hidden",
          boxShadow: h
            ? "0 20px 52px rgba(125,27,43,.28)"
            : "0 6px 24px rgba(0,0,0,.13)",
          transition: "transform .35s ease, box-shadow .35s ease",
          transform: h ? "translateY(-6px)" : "translateY(0)",
          background: C.white,
        }}
      >
        {/* ── Área de imagen: blur de fondo + foto completa centrada ── */}
        <div style={{
          position: "relative",
          height: 290,
          overflow: "hidden",
          background: "#1A0810",
        }}>
          {/* Capa de fondo difuminada — rellena el espacio sin recortar la foto */}
          <img
            src={src}
            alt=""
            aria-hidden="true"
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              objectFit: "cover",
              filter: "blur(18px) brightness(0.36) saturate(1.7)",
              transform: "scale(1.12)",
              pointerEvents: "none",
            }}
          />
          {/* Foto principal — completa, sin recortar, centrada */}
          <img
            src={src}
            alt={label}
            onError={() => setErr(true)}
            style={{
              position: "relative",
              zIndex: 1,
              width: "100%",
              height: "100%",
              objectFit: "contain",
              display: "block",
              transition: "transform .35s ease",
              transform: h ? "scale(1.04)" : "scale(1)",
            }}
          />
        </div>

        {/* ── Pie de foto ── */}
        <div style={{
          padding: "15px 18px 18px",
          borderLeft: `4px solid ${C.primary}`,
          background: C.white,
        }}>
          <div style={{
            fontSize: 13,
            fontWeight: 800,
            color: C.primary,
            lineHeight: 1.45,
            marginBottom: desc ? 5 : 0,
          }}>{label}</div>
          {desc && (
            <div style={{
              fontSize: 11.5,
              color: C.muted,
              lineHeight: 1.65,
              fontStyle: "italic",
            }}>{desc}</div>
          )}
        </div>
      </div>
    );
  }

  // Placeholder cuando la foto no carga
  return (
    <div
      onMouseEnter={() => setH(true)}
      onMouseLeave={() => setH(false)}
      style={{
        border: `2px dashed ${h ? C.primary : C.light}`,
        borderRadius: 20,
        padding: "28px 18px",
        textAlign: "center",
        background: h ? C.veryLight : "#FFFBFD",
        cursor: "pointer",
        transition: "all .3s ease",
        transform: h ? "translateY(-4px)" : "translateY(0)",
        minHeight: 340,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 12,
      }}
    >
      <div style={{ fontSize: 44, filter: h ? "none" : "grayscale(40%)", transition: "filter .3s" }}>📷</div>
      <div style={{ color: h ? C.primary : C.muted, fontSize: 12, fontWeight: 700, lineHeight: 1.5, padding: "0 6px" }}>{label}</div>
      {desc && <div style={{ color: C.muted, fontSize: 11, lineHeight: 1.55, fontStyle: "italic", padding: "0 6px" }}>{desc}</div>}
      <div style={{ color: C.light, fontSize: 10, fontWeight: 600, marginTop: 4 }}>Agregar foto</div>
    </div>
  );
}

// ─── HEART PARTICLE ────────────────────────────────────────────────────────
function HeartRain() {
  const hearts = ["❤️","🌹","💕","💑","✨","💫"];
  return (
    <div style={{ position:"absolute", inset:0, overflow:"hidden", pointerEvents:"none" }}>
      {[...Array(12)].map((_,i) => (
        <div key={i} style={{
          position:"absolute",
          fontSize: `${14 + (i*7)%18}px`,
          left:`${(i*137)%90}%`,
          top:`${(i*93)%85}%`,
          opacity:0.13,
          animation:`fl ${3+(i%4)}s ease-in-out infinite`,
          animationDelay:`${i*0.4}s`,
        }}>{hearts[i%hearts.length]}</div>
      ))}
    </div>
  );
}

